all\": 1\r\n        },\r\n        \"actionDurationsMs\": {\r\n            \"basicAttack\": 450,\r\n            \"recall\": 1200\r\n        },\r\n        \"actionMovementLocks\": {\r\n            \"basicAttack\": true,\r\n            \"recall\": true\r\n        },\r\n        \"standbyDelayMs\": 15000\r\n    },\r\n    \"voices\": {\r\n        \"_doc\": \"语音配置\",\r\n        \"customWheel\": [\r\n            {\r\n                \"id\": \"taunt\",\r\n                \"label\": \"嘲讽\",\r\n                \"emoji\": \"😏\",\r\n                \"voiceUrls\": [\r\n                    \"https://cdn.xiaojingge.com/3d-battle/models/heroes/ashe/voices/taunt-1.wav\",\r\n                    \"https://cdn.xiaojingge.com/3d-battle/models/heroes/ashe/voices/taunt-2.wav\",\r\n                    \"https://cdn.xiaojingge.com/3d-battle/models/heroes/ashe/voices/taunt-3.wav\"\r\n                ],\r\n                \"voiceVolume\": 0.85\r\n            },\r\n            {\r\n                \"id\": \"joke\",\r\n                \"label\": \"玩笑\",\r\n                \"emoji\": \"🤣\",\r\n                \"voiceUrls\": [\r\n                    \"https://cdn.xiaojingge.com/3d-battle/models/heroes/ashe/voices/joke-1.wav\",\r\n                    \"https://cdn.xiaojingge.com/3d-battle/models/heroes/ashe/voices/joke-2.wav\",\r\n                    \"https://cdn.xiaojingge.com/3d-battle/models/heroes/ashe/voices/joke-3.wav\"\r\n                ],\r\n                \"voiceVolume\": 0.85\r\n            },\r\n            {\r\n                \"id\": \"provocation‌\",\r\n                \"label\": \"挑衅\",\r\n                \"emoji\": \"💃\",\r\n                \"voiceUrls\": [\r\n                    \"https://cdn.xiaojingge.com/3d-battle/models/heroes/ashe/voices/provocation‌-1.wav\",\r\n                    \"https://cdn.xiaojingge.com/3d-battle/models/heroes/ashe/voices/provocation‌-2.wav\"\r\n                ],\r\n                \"voiceVolume\": 0.85\r\n            },\r\n            {\r\n        