-- 召唤师技能表
CREATE TABLE IF NOT EXISTS `fish_battle_summoner_spell` (
    `id` BIGINT NOT NULL AUTO_INCREMENT,
    `spell_id` VARCHAR(32) NOT NULL COMMENT '技能唯一标识（如 flash, heal, ignite）',
    `name` VARCHAR(64) NOT NULL COMMENT '中文名',
    `icon` VARCHAR(512) DEFAULT NULL COMMENT '图标URL或emoji',
    `description` VARCHAR(512) DEFAULT NULL COMMENT '技能描述',
    `cooldown` INT DEFAULT 0 COMMENT '冷却时间(秒)',
    `asset_config`  LONGTEXT DEFAULT NULL COMMENT '召唤师技能配置JSON',
    `status` TINYINT DEFAULT 1 COMMENT '状态（0禁用/1启用）',
    `create_time` DATETIME DEFAULT CURRENT_TIMESTAMP,
    `update_time` DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_spell_id` (`spell_id`)
    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='摸鱼大乱斗召唤师技能表';

-- 召唤师技能表数据
INSERT INTO `fish`.`fish_battle_summoner_spell` (`id`, `spell_id`, `name`, `icon`, `description`, `cooldown`, `asset_config`, `status`, `create_time`, `update_time`) VALUES (1, 'flash', '闪现', 'https://ddragon.leagueoflegends.com/cdn/14.3.1/img/spell/SummonerFlash.png', '瞬间传送到目标位置附近', 0, '{\r\n    \"_doc\": \"闪现运行时配置。标准 JSON 不支持注释，因此使用 _doc / _comment 字段说明含义。\",\r\n    \"skillId\": \"flash\",\r\n    \"_comment_skillId\": \"技能唯一标识，需要与 fish_battle_summoner_spell.spell_id 一致。\",\r\n    \"slot\": \"summonerD\",\r\n    \"_comment_slot\": \"默认技能槽位；运行时会按玩家实际选择覆盖为 summonerD 或 summonerF。\",\r\n    \"name\": \"闪现\",\r\n    \"initialLevel\": 1,\r\n    \"cast\": {\r\n        \"type\": \"target_point\",\r\n        \"_comment_type\": \"施法目标类型。target_point 表示需要选择地面目标点。\",\r\n        \"range\": 8,\r\n        \"_comment_range\": \"最大施法距离，单位为战斗场景世界坐标。\",\r\n        \"castTimeMs\": 0,\r\n        \"backswingMs\": 0,\r\n        \"lockMovement\": false,\r\n        \"alwaysSmartCast\": true,\r\n        \"_comment_alwaysSmartCast\": \"始终以智能施法模式释放，按键后直接朝鼠标方向施法，无需瞄准确认。\"\r\n    },\r\n    \"cooldown\": {\r\n        \"baseMs\": 12000,\r\n        \"_comment_baseMs\": \"冷却时间，单位毫秒。\"\r\n    },\r\n    \"cost\": {\r\n        \"resourceType\": \"none\",\r\n        \"amount\": 0\r\n    },\r\n    \"effects\": {\r\n        \"onActivate\": [\r\n            {\r\n                \"type\": \"Teleport\",\r\n                \"_comment_type\": \"后端当前已支持 Teleport，会把施法者传送到 targetPoint。\"\r\n            }\r\n        ],\r\n        \"onImpact\": [],\r\n        \"onSuccessCast\": []\r\n    }\r\n}', 1, '2026-04-28 19:57:31', '2026-04-28 21:58:37');
INSERT INTO `fish`.`fish_battle_summoner_spell` (`id`, `spell_id`, `name`, `icon`, `description`, `cooldown`, `asset_config`, `status`, `create_time`, `update_time`) VALUES (2, 'heal', '治疗', 'https://ddragon.leagueoflegends.com/cdn/14.3.1/img/spell/SummonerHeal.png', '恢复自身和附近友军生命值，并为自己提供短暂加速', 0, '{\r\n    \"_doc\": \"治疗运行时配置。\",\r\n    \"skillId\": \"heal\",\r\n    \"_comment_skillId\": \"技能唯一标识。\",\r\n    \"slot\": \"summonerF\",\r\n    \"name\": \"治疗\",\r\n    \"initialLevel\": 1,\r\n    \"cast\": {\r\n        \"type\": \"self_cast\",\r\n        \"_comment_type\": \"self_cast 表示无需瞄准，按键后直接对自己释放。\",\r\n        \"range\": 0,\r\n        \"castTimeMs\": 0,\r\n        \"backswingMs\": 0,\r\n        \"lockMovement\": false\r\n    },\r\n    \"cooldown\": {\r\n        \"baseMs\": 12000,\r\n        \"_comment_baseMs\": \"冷却时间，单位毫秒。\"\r\n    },\r\n    \"cost\": {\r\n        \"resourceType\": \"none\",\r\n        \"amount\": 0\r\n    },\r\n    \"effects\": {\r\n        \"onActivate\": [\r\n            {\r\n                \"type\": \"Heal\",\r\n                \"amount\": 120,\r\n                \"targetMode\": \"self\",\r\n                \"_comment\": \"先给自己回复 120 点生命值。\"\r\n            },\r\n            {\r\n                \"type\": \"Heal\",\r\n                \"amount\": 90,\r\n                \"targetMode\": \"radius\",\r\n                \"radius\": 5,\r\n                \"_comment_radius\": \"半径治疗范围。\",\r\n                \"targetRules\": {\r\n                    \"allyOnly\": true,\r\n                    \"allowSelf\": false,\r\n                    \"_comment\": \"只治疗友军，且不重复治疗自己。\"\r\n                }\r\n            },\r\n            {\r\n                \"type\": \"ApplyStatus\",\r\n                \"statusId\": \"generic_move_speed_up\",\r\n                \"_comment_statusId\": \"状态效果唯一标识。\",\r\n                \"durationMs\": 1000,\r\n                \"stacks\": 1,\r\n                \"targetMode\": \"self\"\r\n            }\r\n        ],\r\n        \"onImpact\": [],\r\n        \"onSuccessCast\": []\r\n    }\r\n}', 1, '2026-04-28 19:57:31', '2026-04-28 21:23:01');
INSERT INTO `fish`.`fish_battle_summoner_spell` (`id`, `spell_id`, `name`, `icon`, `description`, `cooldown`, `asset_config`, `status`, `create_time`, `update_time`) VALUES (3, 'ghost', '疾跑', 'https://ddragon.leagueoflegends.com/cdn/14.3.1/img/spell/SummonerHaste.png', '在持续时间内提高自身移动速度', 0, '{\r\n    \"_doc\": \"疾跑运行时配置。\",\r\n    \"skillId\": \"ghost\",\r\n    \"slot\": \"summonerD\",\r\n    \"name\": \"疾跑\",\r\n    \"initialLevel\": 1,\r\n    \"cast\": {\r\n        \"type\": \"self_cast\",\r\n        \"range\": 0,\r\n        \"castTimeMs\": 0,\r\n        \"backswingMs\": 0,\r\n        \"lockMovement\": false\r\n    },\r\n    \"cooldown\": {\r\n        \"baseMs\": 12000,\r\n        \"_comment_baseMs\": \"冷却时间，单位毫秒。\"\r\n    },\r\n    \"cost\": {\r\n        \"resourceType\": \"none\",\r\n        \"amount\": 0\r\n    },\r\n    \"effects\": {\r\n        \"onActivate\": [\r\n            {\r\n                \"type\": \"ApplyStatus\",\r\n                \"statusId\": \"summoner_ghost_speed_up\",\r\n                \"durationMs\": 10000,\r\n                \"stacks\": 1,\r\n                \"targetMode\": \"self\",\r\n                \"_comment\": \"给自己施加 10 秒移速增益状态。\"\r\n            }\r\n        ],\r\n        \"onImpact\": [],\r\n        \"onSuccessCast\": []\r\n    }\r\n}', 1, '2026-04-28 19:57:31', '2026-04-28 21:59:05');


-- 英雄皮肤表
CREATE TABLE IF NOT EXISTS `fish_battle_hero_skin` (
    `id` BIGINT NOT NULL AUTO_INCREMENT,
    `hero_id` VARCHAR(32) NOT NULL COMMENT '关联英雄标识',
    `skin_id` VARCHAR(64) NOT NULL COMMENT '皮肤唯一标识（如 yasuo_default）',
    `skin_name` VARCHAR(128) NOT NULL COMMENT '皮肤名称',
    `splash_art` VARCHAR(512) DEFAULT NULL COMMENT '皮肤立绘URL',
    `model_url` VARCHAR(512) DEFAULT NULL COMMENT '皮肤3D模型URL',
    `asset_config`  LONGTEXT DEFAULT NULL COMMENT '英雄皮肤展示资产配置JSON',
    `is_default` TINYINT DEFAULT 0 COMMENT '是否默认皮肤（1是/0否）',
    `status` TINYINT DEFAULT 1 COMMENT '状态（0禁用/1启用）',
    `create_time` DATETIME DEFAULT CURRENT_TIMESTAMP,
    `update_time` DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_skin_id` (`skin_id`),
    KEY `idx_hero_id` (`hero_id`)
    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='摸鱼大乱斗英雄皮肤表';

