-- 对局记录表
CREATE TABLE IF NOT EXISTS `fish_battle_game` (
    `id`                BIGINT          NOT NULL AUTO_INCREMENT COMMENT '主键ID',
    `room_id`           BIGINT          NOT NULL COMMENT '关联房间ID',
    `game_mode`         VARCHAR(16)     NOT NULL DEFAULT 'classic' COMMENT '游戏模式',
    `winning_team`      VARCHAR(8)      DEFAULT NULL COMMENT '胜利队伍（blue/red）',
    `blue_kills`        INT             NOT NULL DEFAULT 0 COMMENT '蓝队总击杀',
    `red_kills`         INT             NOT NULL DEFAULT 0 COMMENT '红队总击杀',
    `duration_seconds`  INT             NOT NULL DEFAULT 0 COMMENT '对局时长（秒）',
    `end_reason`        VARCHAR(32)     DEFAULT NULL COMMENT '结束原因（crystal_destroyed/kill_limit）',
    `mvp_user_id`       BIGINT          DEFAULT NULL COMMENT 'MVP用户ID',
    `start_time`        DATETIME        DEFAULT NULL COMMENT '开始时间',
    `end_time`          DATETIME        DEFAULT NULL COMMENT '结束时间',
    `create_time`       DATETIME        NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
    PRIMARY KEY (`id`),
    KEY `idx_room_id` (`room_id`),
    KEY `idx_mvp_user_id` (`mvp_user_id`),
    KEY `idx_start_time` (`start_time`),
    KEY `idx_create_time` (`create_time`)
    ) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '摸鱼大乱斗对局记录表';

-- 玩家对局统计表（单局）
CREATE TABLE IF NOT EXISTS `fish_battle_player_stats` (
    `id`                BIGINT          NOT NULL AUTO_INCREMENT COMMENT '主键ID',
    `game_id`           BIGINT          NOT NULL COMMENT '对局ID',
    `user_id`           BIGINT          NOT NULL COMMENT '用户ID',
    `hero_id`           VARCHAR(32)     NOT NULL COMMENT '使用的英雄ID',
    `team`              VARCHAR(8)      NOT NULL COMMENT '所在队伍（blue/red）',
    `kills`             INT             NOT NULL DEFAULT 0 COMMENT '击杀数',
    `deaths`            INT             NOT NULL DEFAULT 0 COMMENT '死亡数',
    `assists`           INT             NOT NULL DEFAULT 0 COMMENT '助攻数',
    `damage_dealt`      INT             NOT NULL DEFAULT 0 COMMENT '输出伤害',
    `damage_taken`      INT             NOT NULL DEFAULT 0 COMMENT '承受伤害',
    `healing`           INT             NOT NULL DEFAULT 0 COMMENT '治疗量',
    `is_mvp`            TINYINT         NOT NULL DEFAULT 0 COMMENT '是否MVP（0否/1是）',
    `is_win`            TINYINT         NOT NULL DEFAULT 0 COMMENT '是否胜利（0否/1是）',
    `likes`             INT             NOT NULL DEFAULT 0 COMMENT '获赞数',
    `points_earned`     INT             NOT NULL DEFAULT 0 COMMENT '本局获得积分',
    `create_time`       DATETIME        NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
    PRIMARY KEY (`id`),
    KEY `idx_game_id` (`game_id`),
    KEY `idx_user_id` (`user_id`),
    UNIQUE KEY `uk_game_user` (`game_id`, `user_id`),
    KEY `idx_hero_id` (`hero_id`)
    ) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '摸鱼大乱斗玩家对局统计表';

-- 玩家总体统计表
CREATE TABLE IF NOT EXISTS `fish_battle_user_stats` (
    `id`                BIGINT          NOT NULL AUTO_INCREMENT COMMENT '主键ID',
    `user_id`           BIGINT          NOT NULL COMMENT '用户ID',
    `total_games`       INT             NOT NULL DEFAULT 0 COMMENT '总场次',
    `wins`              INT             NOT NULL DEFAULT 0 COMMENT '胜场',
    `losses`            INT             NOT NULL DEFAULT 0 COMMENT '败场',
    `total_kills`       INT             NOT NULL DEFAULT 0 COMMENT '总击杀',
    `total_deaths`      INT             NOT NULL DEFAULT 0 COMMENT '总死亡',
    `total_assists`     INT             NOT NULL DEFAULT 0 COMMENT '总助攻',
    `mvp_count`         INT             NOT NULL DEFAULT 0 COMMENT 'MVP次数',
    `current_streak`    INT             NOT NULL DEFAULT 0 COMMENT '当前连胜（负数表示连败）',
    `max_streak`        INT             NOT NULL DEFAULT 0 COMMENT '最大连胜',
    `today_games`       INT             NOT NULL DEFAULT 0 COMMENT '今日已玩场次',
    `today_date`        DATE            DEFAULT NULL COMMENT '今日日期（用于每日重置计数）',
    `daily_limit`       INT             NOT NULL DEFAULT 20 COMMENT '每日对局上限',
    `create_time`       DATETIME        NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
    `update_time`       DATETIME        NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_user_id` (`user_id`)
    ) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '摸鱼大乱斗玩家总体统计表';


-- =========================================================================
-- 摸鱼大乱斗 游戏配置表 + 初始化数据
-- 配置统一由数据库管理，前端通过 REST API 获取
-- =========================================================================

-- 游戏配置表（单表大JSON模式，config_key 区分不同配置类型）
CREATE TABLE IF NOT EXISTS `fish_battle_config` (
    `id`          BIGINT       NOT NULL AUTO_INCREMENT COMMENT '主键ID',
    `config_key`  VARCHAR(64)  NOT NULL COMMENT '配置唯一标识（如 map_default / game_default）',
    `config_data` LONGTEXT     NOT NULL COMMENT '配置数据（JSON格式，_doc字段为中文注释）',
    `description` VARCHAR(256) DEFAULT NULL COMMENT '配置说明',
    `status`      TINYINT      NOT NULL DEFAULT 1 COMMENT '状态（0禁用/1启用）',
    `create_time` DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
    `update_time` DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_config_key` (`config_key`)
    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='摸鱼大乱斗游戏配置表';


-- =========================================================================
-- 1. 地图场景配置 (config_key = 'map_default')
-- 包含：地图边界、出生点、建筑（塔/水晶/枢纽）、补血道具、草丛、泉水、
--       小兵属性、桥面视觉、中央遗迹 等全部场景数据
-- =========================================================================
INSERT INTO `fish`.`fish_battle_config` (`id`, `config_key`, `config_data`, `description`, `status`, `create_time`, `update_time`) VALUES (1, 'map_default', '{\r\n    \"_doc\": \"战斗地图共享配置（Single Source of Truth）。后端 Java 启动时加载为 BattleMapConfig Bean，前端通过 GET /fishBattle/mapConfig 拉取。修改此文件即可同时影响前后端，无需两边分别改代码。JSON 不支持注释，所有 _doc 字段仅供阅读，程序通过 @JsonIgnoreProperties(ignoreUnknown=true) 自动忽略。\",\r\n    \"map\": {\r\n        \"_doc\": \"地图基础尺寸与可走区域边界\",\r\n        \"width\": 160,\r\n        \"depth\": 54,\r\n        \"bridgeWidth\": 40,\r\n        \"bridgeLength\": 270,\r\n        \"playableBounds\": {\r\n            \"_doc\": \"英雄/小兵可走区域边界，超出会被钳位\",\r\n            \"minX\": -130,\r\n            \"maxX\": 130,\r\n            \"minZ\": -19.6,\r\n            \"maxZ\": 19.6\r\n        }\r\n    },\r\n    \"spawnLayouts\": {\r\n        \"_doc\": \"英雄初始出生编队坐标 [x, y, z]，最多 5 人\",\r\n        \"blue\": [\r\n            [\r\n                -125,\r\n                0,\r\n                -5\r\n            ],\r\n            [\r\n                -120,\r\n                0,\r\n                -2\r\n            ],\r\n            [\r\n                -125,\r\n                0,\r\n                0\r\n            ],\r\n            [\r\n                -120,\r\n                0,\r\n                2\r\n            ],\r\n            [\r\n                -125,\r\n                0,\r\n                5\r\n            ]\r\n        ],\r\n        \"red\": [\r\n            [\r\n                125,\r\n                0,\r\n                -5\r\n            ],\r\n            [\r\n                120,\r\n                0,\r\n                -2\r\n            ],\r\n            [\r\n                125,\r\n                0,\r\n                0\r\n            ],\r\n            [\r\n                120,\r\n                0,\r\n                2\r\n            ],\r\n            [\r\n                125,\r\n                0,\r\n                5\r\n            ]\r\n        ]\r\n    },\r\n    \"structures\": {\r\n        \"_doc\": \"所有建筑定义。position=[x,y,z]，collisionRadius=碰撞半径，maxHp=最大血量，armor=护甲\",\r\n        \"towers\": [\r\n            {\r\n                \"_doc\": \"蓝队外塔\",\r\n                \"id\": \"tower_0\",\r\n                \"team\": \"blue\",\r\n                \"subType\": \"outer\",\r\n                \"position\": [\r\n                    -25,\r\n                    0,\r\n                    0\r\n                ],\r\n                \"collisionRadius\": 2.5,\r\n                \"maxHp\": 3000,\r\n                \"armor\": 40,\r\n                \"attackDamage\": 200,\r\n                \"attackRange\": 15,\r\n                \"attackSpeed\": 0.63\r\n            },\r\n            {\r\n                \"_doc\": \"蓝队内塔\",\r\n                \"id\": \"tower_1\",\r\n                \"team\": \"blue\",\r\n                \"subType\": \"inner\",\r\n                \"position\": [\r\n                    -55,\r\n                    0,\r\n                    0\r\n                ],\r\n                \"collisionRadius\": 2.5,\r\n                \"maxHp\": 4000,\r\n                \"armor\": 40,\r\n                \"attackDamage\": 200,\r\n                \"attackRange\": 15,\r\n                \"attackSpeed\": 0.63\r\n            },\r\n            {\r\n                \"_doc\": \"蓝队左门牙塔\",\r\n                \"id\": \"tower_2\",\r\n                \"team\": \"blue\",\r\n                \"subType\": \"nexusGuard\",\r\n                \"position\": [\r\n                    -100,\r\n                    0,\r\n                    -5.4\r\n                ],\r\n                \"collisionRadius\": 2.5,\r\n                \"maxHp\": 3500,\r\n                \"armor\": 40,\r\n                \"attackDamage\": 200,\r\n                \"attackRange\": 15,\r\n                \"attackSpeed\": 0.83\r\n            },\r\n            {\r\n                \"_doc\": \"蓝队右门牙塔\",\r\n                \"id\": \"tower_3\",\r\n                \"team\": \"blue\",\r\n                \"subType\": \"nexusGuard\",\r\n                \"position\": [\r\n                    -100,\r\n                    0,\r\n                    5.4\r\n                ],\r\n                \"collisionRadius\": 2.5,\r\n                \"maxHp\": 3500,\r\n                \"armor\": 40,\r\n                \"attackDamage\": 200,\r\n                \"attackRange\": 15,\r\n                \"attackSpeed\": 0.83\r\n            },\r\n            {\r\n                \"_doc\": \"红队外塔\",\r\n                \"id\": \"tower_4\",\r\n                \"team\": \"red\",\r\n                \"subType\": \"outer\",\r\n                \"position\": [\r\n                    25,\r\n                    0,\r\n                    0\r\n                ],\r\n                \"collisionRadius\": 2.5,\r\n                \"maxHp\": 3000,\r\n                \"armor\": 40,\r\n                \"attackDamage\": 200,\r\n                \"attackRange\": 15,\r\n                \"attackSpeed\": 0.63\r\n            },\r\n            {\r\n                \"_doc\": \"红队内塔\",\r\n                \"id\": \"tower_5\",\r\n                \"team\": \"red\",\r\n                \"subType\": \"inner\",\r\n                \"position\": [\r\n                    55,\r\n                    0,\r\n                    0\r\n                ],\r\n                \"collisionRadius\": 2.5,\r\n                \"maxHp\": 4000,\r\n                \"armor\": 40,\r\n                \"attackDamage\": 200,\r\n                \"attackRange\": 15,\r\n                \"attackSpeed\": 0.63\r\n            },\r\n            {\r\n                \"_doc\": \"红队左门牙塔\",\r\n                \"id\": \"tower_6\",\r\n                \"team\": \"red\",\r\n                \"subType\": \"nexusGuard\",\r\n                \"position\": [\r\n                    100,\r\n                    0,\r\n                    -5.4\r\n                ],\r\n                \"collisionRadius\": 2.5,\r\n                \"maxHp\": 3500,\r\n                \"armor\": 40,\r\n                \"attackDamage\": 200,\r\n                \"attackRange\": 15,\r\n                \"attackSpeed\": 0.83\r\n            },\r\n            {\r\n                \"_doc\": \"红队右门牙塔\",\r\n                \"id\": \"tower_7\",\r\n                \"team\": \"red\",\r\n                \"subType\": \"nexusGuard\",\r\n                \"position\": [\r\n                    100,\r\n                    0,\r\n                    5.4\r\n                ],\r\n                \"collisionRadius\": 2.5,\r\n                \"maxHp\": 3500,\r\n                \"armor\": 40,\r\n                \"attackDamage\": 200,\r\n                \"attackRange\": 15,\r\n                \"attackSpeed\": 0.83\r\n            }\r\n        ],\r\n        \"towerVisual\": {\r\n            \"_doc\": \"防御塔前端视觉参数（模型路径、动画、尺寸）。后端不使用此节。\",\r\n            \"blue\": {\r\n                \"outerModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/blue_tower.glb\",\r\n                \"outerDestroyedModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/turrets_destroyed.glb\",\r\n                \"innerModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/blue_tower.glb\",\r\n                \"innerDestroyedModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/turrets_destroyed.glb\",\r\n                \"nexusGuardModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/blue_tower.glb\",\r\n                \"nexusGuardDestroyedModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/turrets_destroyed.glb\",\r\n                \"rotationY\": 1.5707963\r\n            },\r\n            \"red\": {\r\n                \"outerModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/red_tower.glb\",\r\n                \"outerDestroyedModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/turrets_destroyed.glb\",\r\n                \"innerModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/red_tower.glb\",\r\n                \"innerDestroyedModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/turrets_destroyed.glb\",\r\n                \"nexusGuardModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/red_tower.glb\",\r\n                \"nexusGuardDestroyedModelPath\": \"https://cdn.xiaojingge.com/3d-battle/models/towers/turrets_destroyed.glb\",\r\n                \"rotationY\": -1.5707963\r\n            },\r\n            \"outer\": {\r\n                \"targetHeight\": 7.6,\r\n                \"modelScale\": 2.5,\r\n                \"groundOffsetY\": -8.3,\r\n                \"destroyedTargetHeight\": 0,\r\n                \"destroyedModelScale\": 0,\r\n                \"destroyedGroundOffsetY\": -5,\r\n                \"idleClip\": \"Idle1_Base\",\r\n                \"deathClip\": \"Idle1_Base\"\r\n            },\r\n            \"inner\": {\r\n                \"targetHeight\": 7.6,\r\n                \"modelScale\": 2.5,\r\n                \"groundOffsetY\": -8.3,\r\n                \"destroyedTargetHeight\": 0,\r\n                \"destroyedModelScale\": 0,\r\n                \"destroyedGroundOffsetY\": -5,\r\n                \"idleClip\": \"Idle1_Base\",\r\n                \"deathClip\": \"Idle1_Base\"\r\n            },\r\n            \"nexusGuard\": {\r\n                \"targetHeight\": 7.6,\r\n                \"modelScale\": 2.5,\r\n                \"groundOffsetY\": -8.3,\r\n                \"destroyedTargetHeight\": 0,\r\n                \"destroyedModelScale\": 0,\r\n                \"destroyedGroundOffsetY\": -5,\r\n                \"idleClip\": \"Idle1_Base\",\r\n                \"deathClip\": \"Idle1_Base\"\r\n            }\r\n        },\r\n        \"inhibitors\": [\r\n            {\r\n                \"_doc\": \"蓝队兵营水晶\",\r\n                \"id\": \"inhibitor_0\",\r\n                \"team\": \"blue\",\r\n                \"position\": [\r\n                    -80,\r\n                    0,\r\n                    0\r\n          